const state = context.get('state') || {
  wind: 8.2,
  volt: 48.6,
  curr: 12.1,
  vib: 2.4,
  temp: 54,
  batt: 75,
  load: 320
};

const jitter = (v, j) => Number((v + (Math.random() * 2 - 1) * j).toFixed(2));
const clamp = (v, min, max) => Math.max(min, Math.min(max, v));

state.wind = clamp(jitter(state.wind, 0.7), 0, 30);
state.volt = clamp(jitter(state.volt, 0.35), 0, 90);
state.curr = clamp(jitter(state.curr, 0.8), 0, 120);
state.vib = clamp(jitter(state.vib, 0.2), 0, 15);
state.temp = clamp(jitter(state.temp, 0.6), -10, 120);
state.load = clamp(jitter(state.load, 8), 100, 3000);
state.batt = clamp(Number((state.batt + (state.wind > 10 ? 0.2 : state.wind < 3 ? -0.6 : -0.1)).toFixed(2)), 0, 100);

context.set('state', state);

msg.headers = {
  "Content-Type": "application/json",
  "x-api-key": env.get("INGEST_API_KEY") || "dev-ingest-key"
};

const apiBase = (env.get("API_BASE") || "http://localhost:3000").replace(/\/+$/, "");
msg.url = `${apiBase}/api/v1/readings/ingest`;

msg.payload = {
  deviceId: env.get("DEVICE_ID") || "AE-01",
  farmId: env.get("FARM_ID") || "FARM-01",
  plotId: env.get("PLOT_ID") || "PLOT-01",
  ts: new Date().toISOString(),
  windSpeedMs: state.wind,
  genVoltageV: state.volt,
  genCurrentA: state.curr,
  vibrationRms: state.vib,
  genTempC: state.temp,
  batteryPct: Math.round(state.batt),
  loadPowerW: Math.round(state.load),
  mode: "node-red"
};

return msg;
